from dataclasses import dataclass
from typing import Optional
import time, hashlib

@dataclass
class GatewayConfig:
    rate_limit_rpm: int = 600          # requests per minute per API key
    max_prompt_tokens: int = 16_000    # reject oversized requests early
    cache_ttl_seconds: int = 3600      # semantic cache TTL
    canary_fraction: float = 0.05      # 5 % to canary model
    timeout_seconds: float = 60.0

    def validate_request(self, prompt_tokens: int, api_key: str) -> Optional[str]:
        """Return an error string or None if the request is valid.""\"
        if prompt_tokens > self.max_prompt_tokens:
            return f"prompt_too_long: {prompt_tokens} > {self.max_prompt_tokens}"
        if not api_key:
            return "missing_api_key"
        return None

class SemanticCache:
    """
    Exact-match cache keyed on prompt hash.
    Production systems use embedding-based approximate matching.
    """
    def __init__(self, ttl: int = 3600):
        self._store: dict[str, tuple[str, float]] = {}
        self.ttl = ttl

    def _key(self, prompt: str) -> str:
        return hashlib.sha256(prompt.encode()).hexdigest()

    def get(self, prompt: str) -> Optional[str]:
        k = self._key(prompt)
        if k in self._store:
            reply, stored_at = self._store[k]
            if time.time() - stored_at < self.ttl:
                return reply
            del self._store[k]
        return None

    def set(self, prompt: str, reply: str) -> None:
        self._store[self._key(prompt)] = (reply, time.time())

from dataclasses import dataclass
from typing import Optional

@dataclass
class GPUNodeConfig:
    instance_type: str          # e.g. "g5.12xlarge" (4× A10G)
    model_id: str               # e.g. "meta-llama/Llama-3-8B-Instruct"
    gpu_memory_utilisation: float = 0.90   # vLLM kwarg
    max_model_len: int = 8192
    tensor_parallel_size: int = 1          # number of GPUs per replica

    @property
    def vllm_launch_args(self) -> list[str]:
        return [
            "python", "-m", "vllm.entrypoints.openai.api_server",
            "--model", self.model_id,
            "--gpu-memory-utilization", str(self.gpu_memory_utilisation),
            "--max-model-len", str(self.max_model_len),
            "--tensor-parallel-size", str(self.tensor_parallel_size),
        ]

@dataclass
class AutoScalingPolicy:
    min_replicas: int = 1
    max_replicas: int = 10
    target_requests_per_replica: int = 20   # scale-out threshold
    scale_down_stabilisation_s: int = 300   # avoid thrash

    def desired_replicas(self, current_rps: float) -> int:
        desired = max(self.min_replicas,
                      int(current_rps / self.target_requests_per_replica) + 1)
        return min(desired, self.max_replicas)

from dataclasses import dataclass
from typing import List, Optional
import numpy as np

@dataclass
class VectorStoreConfig:
    host: str
    port: int = 8080
    collection: str = "documents"
    ef_construction: int = 128     # HNSW build-time parameter
    m: int = 16                    # HNSW connectivity
    index_version: str = "v1"      # bump on each full re-index

    @property
    def connection_url(self) -> str:
        return f"http://{self.host}:{self.port}"

class VectorStoreHealthCheck:
    def __init__(self, config: VectorStoreConfig):
        self.config = config

    def check(self) -> dict:
        """Returns a health summary; integrate with Prometheus health endpoint.""\"
        import urllib.request, json as _json
        url = f"{self.config.connection_url}/v1/.well-known/ready"
        try:
            with urllib.request.urlopen(url, timeout=2) as r:
                return {"status": "ok", "http_code": r.status}
        except Exception as exc:
            return {"status": "error", "error": str(exc)}

import logging, json, sys

class JSONFormatter(logging.Formatter):
    def format(self, record: logging.LogRecord) -> str:
        payload = {
            "level":    record.levelname,
            "logger":   record.name,
            "message":  record.getMessage(),
            "ts":       self.formatTime(record, self.datefmt),
        }
        if hasattr(record, "trace_id"):
            payload["trace_id"] = record.trace_id
        if record.exc_info:
            payload["exception"] = self.formatException(record.exc_info)
        return json.dumps(payload)

def configure_logging() -> None:
    handler = logging.StreamHandler(sys.stdout)
    handler.setFormatter(JSONFormatter())
    root = logging.getLogger()
    root.setLevel(logging.INFO)
    root.addHandler(handler)
